function report = runPhaseASlantedPlaneMatrix(options)
%RUNPHASEASLANTEDPLANEMATRIX Validate contracted along/cross-track slopes.
%
% Each case independently renders a quantized reference/moving pair. Analytic
% slanted-plane homographies provide correspondence and Jacobian truth. The
% tested surface Jacobian is A_surf=A_0+(dw/dZ)*(dZ/dp)^T.
%
% Traceability: algorithm description Secs. 5.3, 10.2, and 14.1;
% Eq. (63), Algorithm 1 geometry, and the Stage 0 synthetic-surface roadmap.

arguments
    options.SlopeDegrees (1, :) double ...
        {mustBeFinite, mustBePositive, ...
        mustBeLessThan(options.SlopeDegrees, 90)} = [10, 25, 40]
    options.ImageSize (1, 2) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = [96, 112]
    options.Display (1, 1) logical = true
end

root = fileparts(fileparts(mfilename("fullpath")));
src = fullfile(root, "src");
oldPath = path;
addpath(src);
cleanup = onCleanup(@() path(oldPath));

ns = numel(options.SlopeDegrees);
slopeDegrees = [options.SlopeDegrees(:); options.SlopeDegrees(:)];
direction = [repmat("along-track", ns, 1); ...
    repmat("cross-track", ns, 1)];
along = [options.SlopeDegrees(:); zeros(ns, 1)];
crossTrack = [zeros(ns, 1); options.SlopeDegrees(:)];
n = numel(slopeDegrees);
p = phaseASlantedPixels(options.ImageSize);
[xf, yf] = meshgrid(1:options.ImageSize(2), 1:options.ImageSize(1));
pf = [xf(:), yf(:)];

minimumHeight = nan(n, 1);
maximumHeight = nan(n, 1);
maximumWarpError = nan(n, 1);
maximumSurfaceJacobianError = nan(n, 1);
referenceValidFraction = nan(n, 1);
movingValidFraction = nan(n, 1);
referenceUniqueDn = nan(n, 1);
movingUniqueDn = nan(n, 1);
maximumDn = nan(n, 1);
renderSeconds = nan(n, 1);

timer = tic;
for k = 1:n
    id = "slanted_" + direction(k) + "_" + string(slopeDegrees(k));
    renderer = SyntheticPinholeRenderer( ...
        id, options.ImageSize, Supersample=2, PsfSigmaPixels=0.5, ...
        AlongTrackSlopeDegrees=along(k), ...
        CrossTrackSlopeDegrees=crossTrack(k), TextureSeed=100 + k);
    geom = HeightSweepGeometry( ...
        renderer.ReferenceCamera, renderer.MovingCamera);

    rt = tic;
    pair = renderer.renderPair;
    renderSeconds(k) = toc(rt);
    referenceValidFraction(k) = nnz(pair.ReferenceValid) ...
        / numel(pair.ReferenceValid);
    movingValidFraction(k) = nnz(pair.MovingValid) ...
        / numel(pair.MovingValid);
    referenceUniqueDn(k) = numel(unique(pair.ReferenceImage));
    movingUniqueDn(k) = numel(unique(pair.MovingImage));
    maximumDn(k) = max([pair.ReferenceImage(:); pair.MovingImage(:)]);

    [zf, ~, ~, vzf] = PinholePlaneOracle.surfaceHeight( ...
        renderer.ReferenceCamera, pf, renderer.TrueHeightMetres, ...
        renderer.SurfaceSlopeENU);
    minimumHeight(k) = min(zf(vzf));
    maximumHeight(k) = max(zf(vzf));

    [z, s, ~, vz] = PinholePlaneOracle.surfaceHeight( ...
        renderer.ReferenceCamera, p, renderer.TrueHeightMetres, ...
        renderer.SurfaceSlopeENU);
    [wt, vt] = PinholePlaneOracle.surfaceCorrespondence( ...
        renderer.ReferenceCamera, renderer.MovingCamera, p, ...
        renderer.TrueHeightMetres, renderer.SurfaceSlopeENU);
    [wg, vg] = geom.warp(p, z);
    maximumWarpError(k) = max( ...
        vecnorm(wg - wt, 2, 2), [], "omitmissing");

    [a0, va] = geom.warpJacobian(p, z, DeltaPixel=0.25);
    [t, ~, vht] = geom.heightDerivative(p, z, DeltaHeight=0.5);
    actual = HeightSweepGeometry.surfaceJacobian(a0, t, s);
    [expected, ve] = PinholePlaneOracle.surfaceWarpJacobian( ...
        renderer.ReferenceCamera, renderer.MovingCamera, p, ...
        renderer.TrueHeightMetres, renderer.SurfaceSlopeENU);
    maximumSurfaceJacobianError(k) = max( ...
        abs(actual - expected), [], "all", "omitmissing");

    if ~all(vz & vt & vg & va & vht & ve)
        error("runPhaseASlantedPlaneMatrix:InvalidContractedSample", ...
            "A contracted slanted-plane sample was geometrically invalid.");
    end
end
seconds = toc(timer);

results = table(direction, slopeDegrees, along, crossTrack, ...
    minimumHeight, maximumHeight, maximumWarpError, ...
    maximumSurfaceJacobianError, referenceValidFraction, ...
    movingValidFraction, referenceUniqueDn, movingUniqueDn, maximumDn, ...
    renderSeconds, VariableNames=["Direction", "SlopeDegrees", ...
    "AlongTrackSlopeDegrees", "CrossTrackSlopeDegrees", ...
    "MinimumHeightMetres", "MaximumHeightMetres", ...
    "MaximumOracleWarpErrorPixels", "MaximumSurfaceJacobianError", ...
    "ReferenceValidFraction", "MovingValidFraction", ...
    "ReferenceUniqueDn", "MovingUniqueDn", "MaximumDn", ...
    "RenderSeconds"]);
summary = struct( ...
    "Cases", height(results), ...
    "MaximumAbsoluteHeightMetres", max(abs( ...
    [minimumHeight; maximumHeight])), ...
    "MaximumOracleWarpErrorPixels", max(maximumWarpError), ...
    "MaximumSurfaceJacobianError", max(maximumSurfaceJacobianError), ...
    "MinimumReferenceValidFraction", min(referenceValidFraction), ...
    "MinimumMovingValidFraction", min(movingValidFraction), ...
    "MaximumDn", max(maximumDn), ...
    "Seconds", seconds);
report = struct("Results", results, "Summary", summary, ...
    "ImageSize", options.ImageSize, "SamplePixels", p);

fprintf("Phase A slanted-plane matrix: %d cases\n", height(results));
fprintf("  Maximum absolute truth height: %.3f m\n", ...
    summary.MaximumAbsoluteHeightMetres);
fprintf("  Max oracle/geometry EPE: %.3e pixels\n", ...
    summary.MaximumOracleWarpErrorPixels);
fprintf("  Max rank-one surface-Jacobian error: %.3e\n", ...
    summary.MaximumSurfaceJacobianError);
fprintf("  Minimum valid fractions [reference moving]: [%.6f %.6f]\n", ...
    summary.MinimumReferenceValidFraction, ...
    summary.MinimumMovingValidFraction);
fprintf("  Runtime: %.3f s\n", seconds);
if options.Display
    disp(results);
end

clear cleanup
end

function p = phaseASlantedPixels(imageSize)
x = linspace(0.2 * imageSize(2), 0.8 * imageSize(2), 4);
y = linspace(0.2 * imageSize(1), 0.8 * imageSize(1), 4);
[xx, yy] = meshgrid(x, y);
p = [xx(:), yy(:)];
end
